// Get won opportunities and filter to last 7 days
const wonOpps = $('GHL Get Won Opportunities').first().json;
const opps = wonOpps.opportunities || wonOpps.data || [];

const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);

const recentWonOpps = opps.filter(opp => {
  const closeDate = new Date(opp.updatedAt || opp.dateUpdated || opp.createdAt);
  return closeDate >= sevenDaysAgo;
});

// Build contact lookup list
const contactRequests = recentWonOpps.map(opp => ({
  contactId: opp.contact?.id || opp.contactId,
  opportunityId: opp.id,
  opportunityName: opp.name || 'Unknown',
  monetaryValue: opp.monetaryValue || 0,
  pipelineId: opp.pipelineId || '',
  pipelineStageId: opp.pipelineStageId || '',
  closeDate: opp.updatedAt || opp.dateUpdated || opp.createdAt,
  status: opp.status
}));

if (contactRequests.length === 0) {
  return [{ json: { contactRequests: [], hasWonOpps: false, wonCount: 0 } }];
}

return [{ json: { contactRequests, hasWonOpps: true, wonCount: contactRequests.length } }];

// Split contactRequests into individual items for batch processing
const data = $input.first().json;
const requests = data.contactRequests || [];

return requests.map(req => ({ json: req }));

// Build attribution record for each won deal
const items = $input.all();
const oppData = $('Split Contact Requests').all();

const closedDeals = items.map((item, index) => {
  const contact = item.json.contact || item.json;
  const opp = oppData[index]?.json || {};

  // Extract attribution/UTM data
  const attributions = contact.attributions || [];
  let dctNumber = 'Unknown';
  let utmSource = '';
  let utmMedium = '';
  let utmCampaign = '';

  // Find the fb_ad attribution (TFM-sourced)
  const fbAttribution = attributions.find(a => 
    a.utmSource === 'fb_ad' || 
    a.utmSource === 'facebookads' ||
    (a.utmCampaign || '').toLowerCase().includes('feed media')
  );

  if (fbAttribution) {
    utmSource = fbAttribution.utmSource || '';
    utmMedium = fbAttribution.utmMedium || '';
    utmCampaign = fbAttribution.utmCampaign || '';

    // Extract DCT number from utmMedium (e.g., "DCT_183_ March 31st")
    const dctMatch = (utmMedium || '').match(/DCT[_\s]*(\d+)/i);
    if (dctMatch) {
      dctNumber = 'DCT ' + dctMatch[1];
    }
  }

  // Check if TFM-attributed
  const isTFMAttributed = !!fbAttribution;

  // Extract webinar date from tags if available
  const tags = contact.tags || [];
  const webinarTag = tags.find(t => 
    (t || '').toLowerCase().includes('webinar') || 
    (t || '').toLowerCase().includes('registered')
  ) || '';

  const contactName = [contact.firstName || '', contact.lastName || ''].filter(Boolean).join(' ') || 'Unknown';

  return {
    json: {
      contactName,
      email: contact.email || '',
      phone: contact.phone || '',
      revenue: opp.monetaryValue || 0,
      dctNumber,
      utmSource,
      utmMedium,
      utmCampaign,
      isTFMAttributed,
      closeDate: opp.closeDate || '',
      contactDateAdded: contact.dateAdded || '',
      webinarTag,
      tags: tags.join(', '),
      opportunityId: opp.opportunityId || '',
      contactId: contact.id || opp.contactId || ''
    }
  };
});

return closedDeals;

// Calculate funnel metrics from all data sources
const wonOppsRaw = $('GHL Get Won Opportunities').first().json;
const discoveryEvents = $('GHL Get Discovery Call Bookings').first().json;
const setterEvents = $('GHL Get Setter Calendar Events').first().json;

const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
const weekOf = sevenDaysAgo.toISOString().split('T')[0];
const weekEnd = new Date().toISOString().split('T')[0];

// --- Won Opportunities ---
const allOpps = wonOppsRaw.opportunities || wonOppsRaw.data || [];
const recentWonOpps = allOpps.filter(opp => {
  const d = new Date(opp.updatedAt || opp.dateUpdated || opp.createdAt);
  return d >= sevenDaysAgo;
});
const totalRevenue = recentWonOpps.reduce((sum, opp) => sum + (parseFloat(opp.monetaryValue) || 0), 0);
const closeCount = recentWonOpps.length;

// --- Discovery Call Events ---
const discEvents = discoveryEvents.events || discoveryEvents.data || [];
const callsBooked = discEvents.length;
const callsShowed = discEvents.filter(e => {
  const status = (e.status || e.appointmentStatus || '').toLowerCase();
  return status === 'showed' || status === 'completed' || status === 'confirmed';
}).length;
const callsNoShow = discEvents.filter(e => {
  const status = (e.status || e.appointmentStatus || '').toLowerCase();
  return status === 'no_show' || status === 'noshow' || status === 'no show';
}).length;

// --- Setter Calendar Events ---
const setEvents = setterEvents.events || setterEvents.data || [];
const setterBooked = setEvents.length;
const setterShowed = setEvents.filter(e => {
  const status = (e.status || e.appointmentStatus || '').toLowerCase();
  return status === 'showed' || status === 'completed' || status === 'confirmed';
}).length;

// --- Derived metrics (Meta spend/registrations will come from Pipeboard or manual input) ---
// Placeholder values — these get overwritten if Meta data is available
let metaSpend = 0;
let metaRegistrations = 0;
let metaImpressions = 0;
let metaClicks = 0;
let metaCPL = 0;

// Calculate ROAS (revenue / spend) — only if spend > 0
const roas = metaSpend > 0 ? (totalRevenue / metaSpend).toFixed(2) : 'N/A (no Meta spend data)';

// Show rate
const showRate = callsBooked > 0 ? ((callsShowed / callsBooked) * 100).toFixed(1) + '%' : 'N/A';

// Close rate (closes / showed)
const closeRate = callsShowed > 0 ? ((closeCount / callsShowed) * 100).toFixed(1) + '%' : 'N/A';

return [{
  json: {
    weekOf,
    weekEnd,
    // Meta metrics (placeholders — update after Pipeboard integration)
    metaSpend,
    metaRegistrations,
    metaImpressions,
    metaClicks,
    metaCPL,
    // GHL funnel metrics
    discoveryCallsBooked: callsBooked,
    discoveryCallsShowed: callsShowed,
    discoveryCallsNoShow: callsNoShow,
    setterCallsBooked: setterBooked,
    setterCallsShowed: setterShowed,
    totalCallsBooked: callsBooked + setterBooked,
    totalCallsShowed: callsShowed + setterShowed,
    // Close metrics
    closes: closeCount,
    totalRevenue,
    roas,
    // Rates
    showRate,
    closeRate,
    // Summary for Slack
    summaryLine: `Week of ${weekOf}: ${closeCount} closes, $${totalRevenue.toLocaleString()} revenue, ${callsBooked} discovery calls booked (${showRate} show rate), ${setterBooked} setter calls`
  }
}];

// Merge Meta insights into funnel metrics
const funnel = $('Calculate Funnel Metrics').first().json;
const metaRaw = $('Meta Ads Get Weekly Insights').first().json;

// Parse Meta insights
const metaData = metaRaw.data || [metaRaw];
const campaign = metaData[0] || {};

const spend = parseFloat(campaign.spend) || 0;
const impressions = parseInt(campaign.impressions) || 0;
const clicks = parseInt(campaign.clicks) || 0;

// Find lead/registration actions
const actions = campaign.actions || [];
const costPerAction = campaign.cost_per_action_type || [];

let registrations = 0;
let cpl = 0;

// Look for lead or complete_registration actions
const leadAction = actions.find(a => 
  a.action_type === 'lead' || 
  a.action_type === 'offsite_conversion.fb_pixel_lead' ||
  a.action_type === 'offsite_conversion.fb_pixel_complete_registration'
);
if (leadAction) {
  registrations = parseInt(leadAction.value) || 0;
}

const cplAction = costPerAction.find(a => 
  a.action_type === 'lead' || 
  a.action_type === 'offsite_conversion.fb_pixel_lead' ||
  a.action_type === 'offsite_conversion.fb_pixel_complete_registration'
);
if (cplAction) {
  cpl = parseFloat(cplAction.value) || 0;
} else if (registrations > 0 && spend > 0) {
  cpl = spend / registrations;
}

// Recalculate ROAS with actual spend
const roas = spend > 0 ? (funnel.totalRevenue / spend).toFixed(2) : 'N/A';

// Booking rate (calls booked / registrations)
const bookingRate = registrations > 0 ? ((funnel.discoveryCallsBooked / registrations) * 100).toFixed(1) + '%' : 'N/A';

return [{
  json: {
    ...funnel,
    metaSpend: spend,
    metaRegistrations: registrations,
    metaImpressions: impressions,
    metaClicks: clicks,
    metaCPL: Math.round(cpl * 100) / 100,
    metaCTR: impressions > 0 ? ((clicks / impressions) * 100).toFixed(2) + '%' : 'N/A',
    roas,
    bookingRate,
    summaryLine: `Week of ${funnel.weekOf}: ${funnel.closes} closes, $${funnel.totalRevenue.toLocaleString()} revenue | ${registrations} registrations at $${cpl.toFixed(2)} CPL ($${spend.toFixed(2)} spend) | ${funnel.discoveryCallsBooked} calls booked (${funnel.showRate} show rate) | ROAS: ${roas}`
  }
}];

